INSERT INTO dictionary (term, definition, category, example, related_terms) VALUES
  ('FOMO', 'Fear Of Missing Out. The emotional impulse to buy into a rallying market without a plan, often at the worst possible time. FOMO leads to chasing pumps and buying tops.', 'trading', 'BTC jumped 15% overnight and you bought at the top because of FOMO — it dropped 10% the next day.', ARRAY['FUD','Bag Holder','Psychology']),
  ('FUD', 'Fear, Uncertainty, and Doubt. Negative information — real or fabricated — spread to shake confidence and drive prices down. Common in crypto media cycles.', 'trading', 'Headlines about a potential crypto ban caused FUD that dropped BTC 8% before being debunked.', ARRAY['FOMO','Sentiment','Fear & Greed Index']),
  ('Shill', 'Aggressively promoting a coin or project, often with hidden financial incentives. Common on social media where influencers pump tokens they hold.', 'crypto', 'That influencer shilled a random altcoin, it pumped 50%, then crashed 80% after they sold.', ARRAY['Pump & Dump','DYOR','FUD']),
  ('REKT', 'Crypto slang for wrecked — suffering a major loss, usually from overleveraged positions or ignoring risk management.', 'trading', 'He went 50x long on a meme coin and got rekt when it dropped 3%.', ARRAY['Liquidation','Leverage','Stop Loss']),
  ('Bag Holder', 'Someone stuck holding an asset at a significant loss, usually after buying the top and refusing to cut losses.', 'trading', 'She bought SOL at the peak and became a bag holder when it dropped 60%.', ARRAY['FOMO','Stop Loss','HODL']),
  ('DYOR', 'Do Your Own Research. A reminder to independently verify claims before investing. Never rely solely on someone else''s recommendation.', 'general', 'The project looked promising but DYOR revealed the team had no track record.', ARRAY['Fundamental Analysis','Shill','FUD']),
  ('Pump & Dump', 'A manipulation scheme where insiders accumulate an asset, hype it to drive the price up, then sell into the rally — leaving retail investors holding the bag.', 'trading', 'The token pumped 200% on fake partnership news, then dumped 90% as insiders sold.', ARRAY['Shill','Whale','DYOR']),
  ('Blockchain', 'A distributed digital ledger that records transactions across a network of computers. Each block contains transaction data and is linked to the previous block, forming an immutable chain.', 'crypto', 'Bitcoin''s blockchain has never been hacked since launch in 2009.', ARRAY['Block','Mining','Decentralization']),
  ('Mining', 'The process of using computing power to validate transactions and add new blocks to a blockchain. Miners are rewarded with newly created coins for their work.', 'crypto', 'Bitcoin miners compete to solve complex math problems — the winner adds the next block and earns the block reward.', ARRAY['Blockchain','Hash Rate','Halving']),
  ('Halving', 'A pre-programmed event where Bitcoin''s mining reward is cut in half roughly every 4 years. Reduces new supply, historically preceding major price rallies.', 'crypto', 'After the 2024 halving, the block reward dropped from 6.25 to 3.125 BTC.', ARRAY['Mining','Supply','Bull Market']),
  ('Hash Rate', 'The total computing power securing a blockchain network. Higher hash rate means more security and mining competition.', 'crypto', 'Bitcoin''s hash rate hit a new all-time high, signaling strong miner confidence.', ARRAY['Mining','Blockchain','Security']),
  ('Gas', 'The fee paid to process transactions on the Ethereum network. Gas prices fluctuate based on network demand.', 'crypto', 'Gas fees spiked to $50 per transaction during the NFT minting frenzy.', ARRAY['Ethereum','Smart Contract','Layer 2']),
  ('Fiat', 'Government-issued currency like USD, EUR, or GBP. Not backed by a physical commodity — its value comes from government decree and public trust.', 'general', 'Most crypto traders convert profits back to fiat (USD) to lock in gains.', ARRAY['Stablecoin','USD','DXY']),
  ('Fork', 'When a blockchain splits into two separate chains, usually due to a disagreement about protocol rules. Hard forks create a new coin.', 'crypto', 'The Ethereum hard fork in 2016 created Ethereum Classic after a dispute over reversing a hack.', ARRAY['Blockchain','Consensus','Protocol']),
  ('ICO', 'Initial Coin Offering. A fundraising method where new crypto projects sell tokens to early investors. Similar to an IPO but largely unregulated.', 'crypto', 'Many 2017 ICOs raised millions but delivered nothing — always DYOR before investing in token sales.', ARRAY['Token','DYOR','Fundamental Analysis']),
  ('KYC', 'Know Your Customer. Identity verification required by regulated exchanges before you can trade or withdraw funds.', 'general', 'Coinbase requires KYC verification before you can deposit or trade.', ARRAY['Exchange','Regulation','Compliance']),
  ('Long/Short', 'Going long means buying expecting the price to rise. Going short means selling expecting the price to fall. Both can use leverage.', 'trading', 'I went long BTC at $70K targeting $80K, with a stop loss at $68K.', ARRAY['Leverage','Margin','Stop Loss']),
  ('Margin', 'The collateral deposited to open a leveraged trading position. Your margin is at risk — if the trade moves against you enough, you get liquidated.', 'trading', 'With $1,000 margin and 10x leverage, you control a $10,000 position.', ARRAY['Leverage','Liquidation','Collateral']),
  ('ROI', 'Return on Investment. The percentage gain or loss on an investment relative to its cost.', 'general', 'Bought BTC at $30K, sold at $75K — that''s a 150% ROI.', ARRAY['P&L','Risk-Reward Ratio','Portfolio']),
  ('Technical Analysis', 'Studying price charts, patterns, and indicators to predict future price movements. Uses moving averages, RSI, Fibonacci, and volume.', 'technical', 'Technical analysis showed BTC forming a bull flag with RSI at 45 — a potential continuation setup.', ARRAY['RSI','SMA','Fibonacci Retracement','Support']),
  ('Fundamental Analysis', 'Evaluating an asset''s intrinsic value by analyzing its technology, team, adoption, and market position — not just price charts.', 'general', 'Fundamental analysis of Ethereum considers developer activity, TVL, and fee revenue.', ARRAY['DYOR','Technical Analysis','Tokenomics']),
  ('Arbitrage', 'Profiting from price differences of the same asset across different exchanges. Buy low on one, sell high on another.', 'trading', 'BTC was $74,000 on Coinbase and $74,200 on Binance — arbitrage traders captured the $200 spread.', ARRAY['Exchange','Spread','Whale']),
  ('ATL', 'All-Time Low. The lowest price an asset has ever traded at.', 'general', 'LUNA hit its ATL of near-zero after the Terra collapse in 2022.', ARRAY['All-Time High','Bear Market','Capitulation']),
  ('Capitulation', 'When investors give up hope and sell at a loss in panic, often marking the bottom of a selloff. Mass capitulation usually signals potential reversal.', 'trading', 'Fear & Greed hit 6 as holders capitulated — BTC bottomed and rallied 400% over the next year.', ARRAY['Fear & Greed Index','Bear Market','HODL']),
  ('Stablecoin', 'A cryptocurrency pegged to a stable asset like the US dollar. Used for trading and storing value without converting to fiat.', 'crypto', 'USDC and USDT maintain a 1:1 peg to the US dollar.', ARRAY['Fiat','DCA','Cash Allocation']),
  ('Smart Contract', 'Self-executing code on a blockchain that automatically enforces agreement terms when conditions are met. No middleman needed.', 'crypto', 'DeFi lending protocols use smart contracts to automatically liquidate undercollateralized loans.', ARRAY['Ethereum','DeFi','Gas']),
  ('DeFi', 'Decentralized Finance. Financial services built on blockchain without banks — includes lending, borrowing, trading, and yield farming.', 'crypto', 'DeFi protocols like Aave let you earn interest on your crypto without a bank account.', ARRAY['Smart Contract','Yield','Liquidity']),
  ('Funding Rate', 'A periodic payment between long and short traders on perpetual futures. Positive rate means longs pay shorts (bullish crowding).', 'trading', 'BTC funding rate spiked to 0.1% — too many longs crowded, increasing long squeeze risk.', ARRAY['Futures','Long/Short','Leverage']),
  ('Open Interest', 'The total number of outstanding futures contracts that haven''t been settled. Rising OI with rising price confirms a strong trend.', 'trading', 'BTC open interest hit $20B while price rallied — confirming conviction behind the move.', ARRAY['Futures','Funding Rate','Volume']),
  ('Slippage', 'The difference between the expected price and the actual execution price. Common in low-liquidity markets or during volatility.', 'trading', 'Slippage caused my order to fill at $73,850 instead of $74,000 due to thin order books.', ARRAY['Liquidity','Spread','Order Book'])
